SELECT EXISTS (
    SELECT 1
    FROM reservations r
    WHERE r.store_id = #{storeId}
      AND r.deleted_at IS NULL
      AND r.event_start_date <= #{eventEndDate}
      AND r.event_end_date >= #{eventStartDate}
      AND r.status IN (
          'CONFIRMED',
          'PAYMENT_COMPLETED',
          'COMPLETED'
      )
)

SELECT m.menu_id, m.name, m.description, m.price, m.image_url FROM menus m WHERE m.store_id = #{storeId} AND m.deleted_at IS NULL AND m.menu_id IN
#{menuId}
ORDER BY m.menu_id
